using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed default discriminator property from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator" — preserve for compatibility.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id format from "EntityType|Key" to just "Key".
            // Existing documents have ids like "Product|123" — preserve for compatibility.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // REMOVED: HasIndex — EF Core 9 Cosmos provider throws at startup.
        // Cosmos DB indexing is managed via the container's indexing policy (Azure Portal/Bicep).
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

